---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"div"> {
  defaultValue?: string
  name?: string
  disabled?: boolean
  readOnly?: boolean
  required?: boolean
}

const {
  class: className,
  defaultValue,
  name,
  disabled,
  readOnly,
  required,
  ...props
} = Astro.props

const booleanDataAttr = (value?: boolean) =>
  value === undefined ? undefined : value ? "" : "false"
---

<div
  data-slot="radio-group"
  data-default-value={defaultValue}
  data-name={name}
  data-disabled={booleanDataAttr(disabled)}
  data-read-only={booleanDataAttr(readOnly)}
  data-required={booleanDataAttr(required)}
  class={cn("grid w-full gap-3", className)}
  {...props}
>
  <slot />
</div>

<script>
  import { create } from "@data-slot/radio-group"

  create()
</script>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"span"> {
  value: string
  disabled?: boolean
  indicatorClass?: string
}

const {
  class: className,
  value,
  disabled,
  indicatorClass,
  ...props
} = Astro.props
---

<span
  data-slot="radio-group-item"
  data-value={value}
  data-disabled={disabled ? "" : undefined}
  class={cn(
    "group/radio-group-item peer border-input dark:bg-input/30 relative flex aspect-square size-4 shrink-0 items-center justify-center rounded-full border outline-none transition-colors after:absolute after:-inset-x-3 after:-inset-y-2 focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 data-[disabled]:cursor-not-allowed data-[disabled]:opacity-50 aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive/20 aria-invalid:aria-checked:border-primary dark:aria-invalid:border-destructive/50 dark:aria-invalid:ring-destructive/40 data-[checked]:border-primary data-[checked]:bg-primary data-[checked]:text-primary-foreground dark:data-[checked]:bg-primary",
    className
  )}
  {...props}
>
  <span
    aria-hidden="true"
    data-slot="radio-group-indicator"
    class={cn(
      "pointer-events-none relative flex size-4 items-center justify-center transition-[opacity,transform] data-[checked]:scale-100 data-[checked]:opacity-100 data-[unchecked]:scale-0 data-[unchecked]:opacity-0",
      indicatorClass
    )}
  >
    <span class="bg-primary-foreground absolute top-1/2 left-1/2 size-2 -translate-x-1/2 -translate-y-1/2 rounded-full" />
  </span>
</span>
